class LUPrefix {
public:
    LUPrefix(int n) {
        nVideos = n;
        firstUploaded = -1;
    }

    void upload(int video) {
        if (video == firstUploaded + 1) {
            firstUploaded++;
        }
    }

    int longest() {
        return firstUploaded + 1;
    }
private:
    int nVideos;
    int firstUploaded;
};
```

